    passage_ids: List[str]
) -> dict[str, Optional[dict[str, object]]]:
    meta_path_str = f"{index_path}.meta.json"
    if not Path(meta_path_str).exists():
        raise FileNotFoundError(f"LEANN metadata file not found at {meta_path_str}")

    with open(meta_path_str) as f:
        meta = json.load(f)

    passage_sources = meta.get("passage_sources")
    if not passage_sources:
        raise ValueError("No passage sources found in LEANN metadata")

    manager = PassageManager(passage_sources=passage_sources)
    result = {}

    for pid in passage_ids:
        try:
            passage = manager.get_passage(pid)
            result[pid] = {
                "id": passage["id"],
                "text": passage["text"],
                "metadata": passage["metadata"]
            }
        except PassageNotFoundError:
            result[pid] = None

    return result

