def search_with_metadata_filtering(
    index_path: str,
    query: str,
    metadata_filters: Optional[dict[str, dict[str, Any]]] = None,
    top_k: int = 5
) -> List[SearchResult]:
    """Search in an index and apply metadata filters to results.

    Args:
        index_path: Path to the LEANN index file
        query: Search query string
        metadata_filters: Optional filters to apply to metadata.
            Format: {"field_name": {"operator": value}}
            Supported operators:
            - Comparison: "==", "!=", "<", "<=", ">", ">="
            - Membership: "in", "not_in"
        top_k: Number of nearest neighbors to return (default: 5)

    Returns:
        Filtered list of SearchResult objects
    """
    # Handle case where metadata_filters is None
    if metadata_filters is None:
        metadata_filters = {}

    # Check if index file exists
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"LEANN index file not found at {index_path}")

    # Load the LEANN index and perform search
    searcher = LeannSearcher(index_path=index_path)
    results = searcher.search(
        query,
        complexity=64,
        beam_width=1,
        prune_ratio=0.0,
        recompute_embeddings=True,
        pruning_strategy='global',
        top_k=top_k
    )

    # Apply metadata filters
    filtered_results = []
    for result in results:
        passes_all_filters = True
        for field, condition in metadata_filters.items():
            if field not in result.metadata:
                passes_all_filters = False
                break

            op = list(condition.keys())[0]
            target = condition[op]
            actual = result.metadata[field]

            # Type check to prevent runtime errors
            try:
                if op == "==":
                    if actual != target:
                        passes_all_filters = False
                        break
                elif op == "!=":
                    if actual == target:
                        passes_all_filters = False
                        break
                elif op == "<":
                    if actual >= target:
                        passes_all_filters = False
                        break
                elif op == "<=":
                    if actual > target:
                        passes_all_filters = False
                        break
                elif op == ">":
                    if actual <= target:
                        passes_all_filters = False
                        break
                elif op == ">=":
                    if actual < target:
                        passes_all_filters = False
                        break
                # Membership checks
                elif op == "in":
                    if not isinstance(target, list) or actual not in target:
                        passes_all_filters = False
                        break
                elif op == "not_in":
                    if not isinstance(target, list) or actual in target:
                        passes_all_filters = False
                        break
                else:
                    # Invalid operator, skip this filter
                    continue
            except (TypeError, ValueError):
                # Skip if comparison fails due to type mismatch
                passes_all_filters = False
                break

        if passes_all_filters:
            filtered_results.append(result)

    return filtered_results

