def build_index_with_metadata_validation(
    documents: List[dict],
    index_path: str,
    required_metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    # Validate documents list is not empty
    if not documents:
        raise ValueError("documents list is empty")

    # Validate required metadata fields
    errors = []
    for i, doc in enumerate(documents):
        if required_metadata_fields is not None:
            # Check if metadata exists
            if 'metadata' not in doc:
                # If required fields are specified, this is an error
                if required_metadata_fields:
                    errors.append(f"Document {i} is missing 'metadata' key")
            else:
                # Check each required field
                for field in required_metadata_fields:
                    if field not in doc['metadata']:
                        errors.append(f"Document {i} is missing required field '{field}'")

    if errors:
        error_msg = "missing required metadata fields:\n" + "\n".join(errors)
        raise ValueError(error_msg)

    # Build the index
    texts = [doc['text'] for doc in documents]
    ids = [str(i) for i in range(len(texts))]
    builder = LeannBuilder(backend_name=backend_name)
    builder.build(texts, ids=ids, index_path=index_path)

    # Ensure the index was created
    index_path_str = str(index_path)
    if not Path(index_path_str).exists():
        raise RuntimeError(f"Index was not created at {index_path_str}")

    return index_path_str

