from typing import List, Any, Optional
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def _get_meta_path(index_path: str) -> str:
    index_path_obj = Path(index_path)
    index_dir = index_path_obj.parent
    meta_name = f"{index_path_obj.name}.meta.json"
    return str(index_dir / meta_name)

def get_index_statistics(index_path: str) -> dict[str, Any]:
    meta_path = _get_meta_path(index_path)
    if not Path(meta_path).exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    with open(meta_path) as f:
        passages_meta = json.load(f)

    total = len(passages_meta)
    fields = set()
    value_counts = defaultdict(Counter)

    for passage in passages_meta:
        for field in passage.keys():
            fields.add(field)
        for field, value in passage.items():
            value_counts[field][value] += 1

    field_list = sorted(fields)
    field_value_counts = {field: dict(counts) for field, counts in value_counts.items()}

    return {
        "total_passages": total,
        "metadata_fields": field_list,
        "field_value_counts": field_value_counts
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    meta_path = _get_meta_path(index_path)
    if not Path(meta_path).exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    with open(meta_path) as f:
        passages_meta = json.load(f)

    total = len(passages_meta)
    covered = 0
    field_coverages = {}
    missing = []

    for passage in passages_meta:
        if all(field in passage for field in required_fields):
            covered += 1

    for field in required_fields:
        count = sum(1 for passage in passages_meta if field in passage)
        if count == 0:
            missing.append(field)
        else:
            field_coverages[field] = (count / total) * 100

    coverage_percentage = (covered / total) * 100 if total > 0 else 0.0

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverages,
        "missing_fields": missing
    }

