def get_passages_by_text_contains(
    index_path: str,
    search_text: str,
    case_sensitive: bool = False
) -> List[dict[str, Any]]:
    if not search_text:
        raise ValueError("search_text cannot be empty")

    # Attempt to create PassageManager; raises FileNotFoundError if meta file is missing
    try:
        passage_manager = PassageManager(index_path=index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"LEANN index metadata file not found at {index_path}")

    matched_passages = []
    # Iterate through all passage IDs in the index
    for passage_id in passage_manager.list_passage_ids():
        passage_data = passage_manager.get_passage(passage_id)
        passage_text = passage_data.get('text', '')

        # Check for substring match with optional case sensitivity
        if case_sensitive:
            if search_text in passage_text:
                matched_passages.append(passage_data)
        else:
            if search_text.lower() in passage_text.lower():
                matched_passages.append(passage_data)

    return matched_passages
